import React from 'react';
import '../App.css';

const Clients = () => {
  return (
    <div className="content-section">
      <h1>Our Clients</h1>
      <p>
        We have had the privilege of working with a diverse range of clients
        from various industries. We are proud of the relationships we have built
        and the success stories we have been a part of.
      </p>
      <p>
        Our client portfolio includes startups, small businesses, and large
        enterprises, all of whom trust us to deliver high-quality digital
        solutions.
      </p>
    </div>
  );
};

export default Clients;
